import React from "react";
import {AppBar, Paper, Button} from "@material-ui/core";

const NavBar = () =>{
    return(
        <AppBar position="absolute" variant="outlined" color="primary">
            <Paper>
                <Button color = "inherit">
                    Resume
                </Button>
            </Paper>
        </AppBar>
    )
}
export default NavBar;
